SELECT COUNT(*) AS film_count
FROM movies
WHERE Distributor LIKE '%Warner Bros%';

SELECT COUNT(*) AS days_above_30
FROM seattle_weather
WHERE temp_max > 30;

SELECT
    ROUND(
        100.0 * SUM(CASE WHEN order_status = 'cancelled' THEN 1 ELSE 0 END) / COUNT(*),
        2
    ) AS cancelled_percentage
FROM olist_orders;
